() => {
  // Initialize or get existing data
  var existing = JSON.parse(localStorage.getItem('__orb__') || '[]');
  var seenNames = new Set(existing.map(r => r.name));

  var articles = document.querySelectorAll('article');
  var newEntries = [];

  articles.forEach(function(article) {
    // Get name - link to place
    var nameEl = article.querySelector('a[href*="/place/"]');
    var name = nameEl ? nameEl.textContent.trim() : '';

    if (!name || seenNames.has(name)) return;
    seenNames.add(name);

    // Get rating from img alt
    var ratingImg = article.querySelector('img[alt*="stars"]');
    var rating = '';
    var reviews = '';
    if (ratingImg) {
      var alt = ratingImg.alt || '';
      var ratingMatch = alt.match(/([\d.]+)\s*stars/);
      var reviewsMatch = alt.match(/(\d+)\s*Reviews/);
      rating = ratingMatch ? ratingMatch[1] : '';
      reviews = reviewsMatch ? reviewsMatch[1] : '';
    }

    // Get address - text after "·" that looks like an address
    var fullText = article.textContent || '';
    var lines = fullText.split('\n').filter(function(l) { return l.trim().length > 0; });

    // Address: look for street-like patterns
    var address = '';
    var addressPatterns = /(Level\s*\d+.*?(St|Street|Rd|Road|Ave|Avenue|Dr|Drive|Terrace|Pl|Place)[^\n,]*|[\d]+[\s]+[\w\s]+(St|Street|Rd|Road|Ave|Avenue|Dr|Drive|Terrace|Pl|Place)[^\n,]*|^\d+[\/\-][\w\s]+(St|Street|Rd|Road|Ave|Avenue|Dr|Drive)[^\n,]*)/i;
    lines.forEach(function(line) {
      if (!address && (line.includes('Level') || line.match(/\d+\/\d+.*?(St|Rd|Ave|Street|Road|Drive)/) || line.match(/^\d+[\s]+[\w]+(St|Street|Rd|Road|Drive)/))) {
        address = line.trim();
      }
    });
    if (!address && nameEl) {
      // Try to find address after company name in the text
      var afterName = fullText.replace(name, '');
      var addrMatch = afterName.match(/(Level\s*\d+\/[^\n·]+|[\d]+\/[^\n·]+|\d+[\s]+[\w\s]+(St|Street|Rd|Road|Ave|Avenue|Dr|Drive)[^·\n]*)/);
      if (addrMatch) address = addrMatch[1].trim();
    }

    // Get phone - New Zealand format
    var phone = '';
    var phoneMatch = fullText.match(/\+\d[\d\s\-\(\)]{7,}/);
    if (phoneMatch) phone = phoneMatch[0].trim();

    // Get hours
    var hours = '';
    var hoursMatch = fullText.match(/(Open|Closed)[·\s]+(Opens?\s+[^·]+|Closes?\s+[^·]+)/);
    if (hoursMatch) hours = hoursMatch[0].trim();

    // Get website
    var websiteEl = article.querySelector('a[href*="://"]');
    var website = websiteEl ? websiteEl.href : '';
    // Filter out non-website URLs (like Google redirects)
    if (website && website.includes('google.com') && website.includes('/place/')) {
      website = '';
    }

    // Only include if website exists
    if (website && website.length > 5) {
      newEntries.push({
        name: name,
        rating: rating,
        reviews: reviews,
        address: address,
        phone: phone,
        hours: hours,
        website: website
      });
    }
  });

  var allData = existing.concat(newEntries);
  localStorage.setItem('__orb__', JSON.stringify(allData));

  return {
    total: allData.length,
    newThisBatch: newEntries.length,
    entries: newEntries.map(function(e) { return e.name + ' | ' + e.website; })
  };
}

