() => {
  // Use a global variable on window for accumulation across scrolls
  if (!window.__NZSoftwareData) window.__NZSoftwareData = [];

  var seenNames = new Set(window.__NZSoftwareData.map(r => r.name));
  var articles = document.querySelectorAll('article');
  var newCount = 0;

  articles.forEach(function(article) {
    var nameEl = article.querySelector('a[href*="/place/"]');
    var name = nameEl ? nameEl.textContent.trim() : '';
    if (!name || seenNames.has(name)) return;
    seenNames.add(name);

    var ratingImg = article.querySelector('img[alt*="stars"]');
    var rating = '', reviews = '';
    if (ratingImg) {
      var alt = ratingImg.alt || '';
      var rm = alt.match(/([\d.]+)\s*stars/);
      var rvm = alt.match(/(\d+)\s*Reviews/);
      rating = rm ? rm[1] : '';
      reviews = rvm ? rvm[1] : '';
    }

    // Address: get the line that contains address info (after type, before hours/phone)
    var typeEl = article.querySelector('.fontBodyMedium');
    var fullText = typeEl ? typeEl.textContent : article.textContent;

    // Extract address - pattern after type label and before hours
    var addrParts = [];
    var lines = fullText.split('\n');
    var startedAddr = false;
    lines.forEach(function(line) {
      var t = line.trim();
      if (t === 'Software company') { startedAddr = true; return; }
      if (startedAddr && t.match(/^(Closed|Open|Closes|Opens|Phone)/)) { startedAddr = false; return; }
      if (startedAddr && t.length > 3 && !t.match(/^(Level\s*\d+\/\d+\s+.*|[A-Z][\w\s]{2,}$)/)) {
        // Skip lines that are just business info tags
        if (t.match(/^\+\d/) || t.match(/Closed|Open|Closes|Opens/)) return;
        // Skip wheelchair icon lines
        if (t.includes('Wheelchair accessible')) return;
        if (!addrParts.length && (t.includes('Level') || t.match(/\d+\/\d+/) || t.match(/\d+\s+[A-Z]/) || t.match(/^[A-Z][a-z]+ (St|Street|Rd|Road|Ave|Avenue|Dr|Drive)/))) {
          addrParts.push(t);
        }
      }
    });
    var address = addrParts[0] || '';

    // Phone
    var phone = '';
    var phoneMatch = fullText.match(/\+\d[\d\s\-()]{7,}/);
    if (phoneMatch) phone = phoneMatch[0].trim();

    // Hours
    var hours = '';
    var hoursMatch = fullText.match(/(Open|Closed)[·\s]+(Opens?\s+[^·]+|Closes?\s+[^·]+)/);
    if (hoursMatch) hours = hoursMatch[0].trim();

    // Website
    var websiteEl = article.querySelector('a[href*="://"]');
    var website = '';
    if (websiteEl) {
      var href = websiteEl.href || '';
      if (href && !href.includes('google.com/maps') && !href.includes('plus.google')) {
        website = href;
      }
    }

    if (website && website.length > 5) {
      window.__NZSoftwareData.push({
        name: name,
        rating: rating,
        reviews: reviews,
        address: address,
        phone: phone,
        hours: hours,
        website: website
      });
      newCount++;
    }
  });

  return { total: window.__NZSoftwareData.length, new: newCount, last5: window.__NZSoftwareData.slice(-5).map(function(e) { return e.name + ' | ' + e.website; }) };
}
